#include <iostream>
#include <vector>
using namespace std;

class Solution {
public:
    vector<int> enqueue(vector<int> queue, int element) {
        return queue + vector<int>(&element, &element + 1);
    }
};


int main() {
    int n;
    cin >> n;
    vector<int> q(n);
    for (int i = 0; i < n; i++) {
        cin >> q[i];
    }
    int elem;
    cin >> elem;
    Solution s;
    for (int i : s.enqueue(q, elem)) {
        cout << i << ' ';
    }
    return 0;
}
